+		if flow == nil {
+			t.Fatal("NewClaudeAuthFlow returned nil")
+		}
+		if flow.isRemote {
+			t.Error("isRemote should be false")
+		}
+	})
+
+	t.Run("remote mode", func(t *testing.T) {
+		t.Parallel()
+		flow := NewClaudeAuthFlow(true)
+		if flow == nil {
+			t.Fatal("NewClaudeAuthFlow returned nil")
+		}
+		if !flow.isRemote {
+			t.Error("isRemote should be true")
+		}
+	})
+}
